'use server';

import { planningCenterService } from '@/lib/services';
import { orchestrator } from '@/lib/orchestrator';

export async function syncContactsAction() {
    try {
        console.log('Action: Syncing contacts...');
        const contacts = await planningCenterService.syncContacts();
        return { success: true, count: contacts.length, message: `Successfully synced ${contacts.length} contacts.` };
    } catch (error: any) {
        console.error('Action Error:', error);
        return { success: false, error: error.message };
    }
}

export async function runPipelineAction(date?: string) {
    try {
        console.log('Action: Running pipeline...');
        const logId = await orchestrator.runPipeline(date);
        return { success: true, logId, message: 'Pipeline started successfully.' };
    } catch (error: any) {
        console.error('Action Error:', error);
        return { success: false, error: error.message };
    }
}
