import { Contact } from '../types';
import { Timestamp } from 'firebase/firestore';

const PCO_API_BASE = 'https://api.planningcenteronline.com/people/v2';

export class PlanningCenterService {
    private appId: string;
    private secret: string;

    constructor() {
        this.appId = process.env.PLANNING_CENTER_APP_ID || '';
        this.secret = process.env.PLANNING_CENTER_SECRET || '';
    }

    isEnabled(): boolean {
        return !!this.appId && !!this.secret;
    }

    private getAuthHeader(): string {
        const credentials = Buffer.from(`${this.appId}:${this.secret}`).toString('base64');
        return `Basic ${credentials}`;
    }

    async syncContacts(): Promise<Contact[]> {
        if (!this.isEnabled()) {
            console.warn('Planning Center service is not configured (missing App ID or Secret)');
            return [];
        }

        try {
            // Fetch people from Planning Center
            // Adjust 'per_page' as needed
            const response = await fetch(`${PCO_API_BASE}/people?per_page=50`, {
                headers: {
                    'Authorization': this.getAuthHeader()
                }
            });

            if (!response.ok) {
                console.error(`Planning Center API error: ${response.status} ${response.statusText}`);
                throw new Error(`Failed to fetch contacts: ${response.statusText}`);
            }

            const data = await response.json();

            // Map PCO people to our Contact interface
            const contacts: Contact[] = data.data.map((person: any) => {
                const now = Timestamp.now();
                return {
                    id: person.id, // Using PCO ID as reference
                    name: `${person.attributes.first_name} ${person.attributes.last_name}`,
                    email: '', // Placeholder as fetching email requires extra call
                    phone: null,
                    whatsappOptIn: false,
                    emailOptIn: false,
                    planningCenterId: person.id,
                    createdAt: person.attributes.created_at ? Timestamp.fromDate(new Date(person.attributes.created_at)) : now,
                    updatedAt: person.attributes.updated_at ? Timestamp.fromDate(new Date(person.attributes.updated_at)) : now,
                };
            });

            console.log(`Synced ${contacts.length} contacts from Planning Center.`);

            // Save to Firestore
            const { upsertContacts } = await import('../firestore');
            await upsertContacts(contacts);

            return contacts;

        } catch (error) {
            console.error('Error syncing Planning Center contacts:', error);
            return [];
        }
    }
}
